+        assert!(!limiter.try_acquire_n(4).await);
+        assert_eq!(limiter.remaining(), 3); // Unchanged
+        // Can take exactly 3
+        assert!(limiter.try_acquire_n(3).await);
+        assert_eq!(limiter.remaining(), 0);
+    }
